class Vector2D {
private:
    double x, y;
public:
    // 생성자 (초기화 리스트)
    Vector2D(double x, double y) : x(x), y(y) {}

    // 연산자 오버로딩
    Vector2D operator+(const Vector2D& other) const {
        return {x + other.x, y + other.y};
    }

    double length() const {
        return sqrt(x*x + y*y);
    }

    void print() const {
        cout << "(" << x << ", " << y << ")" << endl;
    }
};

