class Animal:
    def __init__(self, name, sound):
        self.name = name
        self.sound = sound

    def speak(self):
        return f"{self.name}: {self.sound}!"

class Dog(Animal):
    def __init__(self, name):
        super().__init__(name, "멍멍")

    def fetch(self):
        return f"{self.name}이(가) 공을 가져옵니다!"

dog = Dog("바둑이")
print(dog.speak())
print(dog.fetch())
